+function convertLinks(text: string, options: LinkStyleOptions): string {
+  let result = '';
+  let index = 0;
+
+  while (index < text.length) {
+    const wiki = parseWikiLink(text, index);
+    if (wiki) {
+      const style = wiki.image ? options.imageStyle : options.linkStyle;
+      result += style === 'markdown' ? wikiToMarkdown(wiki) : wiki.source;
+      index = wiki.end;
+      continue;
+    }
+
+    const markdown = parseMarkdownLink(text, index);
+    if (markdown) {
+      const style = markdown.image ? options.imageStyle : options.linkStyle;
+      result += style === 'wiki' ? markdownToWiki(markdown) : markdown.source;
+      index = markdown.end;
+      continue;
+    }
+
+    result += text[index++];
+  }
+
+  return result;
