+  const separator = contents.indexOf('|');
+  const target = separator === -1 ? contents : contents.slice(0, separator);
+  if (!target) return null;
+  return {source: text.slice(start, close + 2), end: close + 2, image, target, display: separator === -1 ? null : contents.slice(separator + 1)};
+}
