+function wikiToMarkdown(link: WikiLink): string {
+  let display = link.display;
+  if (link.image && (display === '300' || /^300x200$/.test(display ?? ''))) display = null;
+  if (display === null) display = link.image ? link.target : defaultHeadingDisplay(link.target) ?? link.target;
+  return `${link.image ? '!' : ''}[${display}](${markdownDestination(link.target)})`;
+}
+
+function markdownDestination(target: string): string {
+  return /\\s/.test(target) ? `<${target}>` : target;
+}
+
+type MarkdownLink = {source: string, end: number, image: boolean, label: string, target: string, hasTitle: boolean};
+
+function parseMarkdownLink(text: string, start: number): MarkdownLink | null {
+  const image = text.startsWith('![', start);
+  const labelStart = start + (image ? 2 : 1);
+  if ((!image && text[start] !== '[') || text.startsWith('[[', start)) return null;
+
+  const labelEnd = findClosingBracket(text, labelStart);
+  if (labelEnd === -1 || text[labelEnd + 1] !== '(') return null;
+  const destinationEnd = findClosingParenthesis(text, labelEnd + 2);
+  if (destinationEnd === -1) return null;
+
+  const rawLabel = text.slice(labelStart, labelEnd);
+  const rawDestination = text.slice(labelEnd + 2, destinationEnd);
+  if (rawLabel.includes('\
') || rawDestination.includes('\
')) return null;
+  const destination = parseDestination(rawDestination);
+  if (!destination || destination.hasTitle || destination.target.includes('://')) return null;
+
+  return {
+    source: text.slice(start, destinationEnd + 1),
+    end: destinationEnd + 1,
+    image,
+    label: unescapeMarkdown(rawLabel),
+    target: unescapeMarkdown(destination.target),
+    hasTitle: destination.hasTitle,
+  };
+}
+
+function findClosingBracket(text: string, start: number): number {
+  let depth = 1;
+  for (let i = start; i < text.length; i++) {
+    if (text[i] === '\\\') {
+      i++;
+    } else if (text[i] === '[') {
+      depth++;
+    } else if (text[i] === ']' && --depth === 0) {
+      return i;
+    }
+  }
+  return -1;
+}
+
+function findClosingParenthesis(text: string, start: number): number {
+  let depth = 1;
+  for (let i = start; i < text.length; i++) {
+    if (text[i] === '\\\') {
+      i++;
+    } else if (text[i] === '(') {
+      depth++;
+    } else if (text[i] === ')' && --depth === 0) {
+      return i;
+    }
+  }
+  return -1;
+}
+
+function parseDestination(value: string): {target: string, hasTitle: boolean} | null {
+  const trimmed = value.trim();
+  if (trimmed.startsWith('<')) {
+    const close = findUnescapedCharacter(trimmed, '>', 1);
+    if (close === -1) return null;
+    return {target: trimmed.slice(1, close), hasTitle: trimmed.slice(close + 1).trim().length > 0};
+  }
+
+  // A space after an unbracketed destination starts a Markdown title.
+  const titleStart = findUnescapedWhitespace(trimmed);
+  return titleStart === -1 ? {target: trimmed, hasTitle: false} : {target: trimmed.slice(0, titleStart), hasTitle: true};
+}
+
+function findUnescapedCharacter(text: string, character: string, start: number): number {
+  for (let i = start; i < text.length; i++) {
+    if (text[i] === '\\\') i++;
+    else if (text[i] === character) return i;
+  }
+  return -1;
+}
+
+function findUnescapedWhitespace(text: string): number {
+  for (let i = 0; i < text.length; i++) {
+    if (text[i] === '\\\') i++;
+    else if (/\\s/.test(text[i])) return i;
+  }
+  return -1;
+}
+
+function unescapeMarkdown(value: string): string {
+  return value.replace(/\\\\(.)/g, '$1');
+}
+
+function markdownToWiki(link: MarkdownLink): string {
+  const display = link.image ? (link.label === '' || link.label === link.target ? null : link.label) :
+    (link.label === link.target || link.label === defaultHeadingDisplay(link.target) ? null : link.label);
+  return `${link.image ? '!' : ''}[[${link.target}${display === null ? '' : `|${display}`}]]`;
+}
+
+function defaultHeadingDisplay(target: string): string | null {
+  const hash = target.indexOf('#');
+  if (hash === -1 || hash === target.length - 1) return null;
+  const page = target.slice(0, hash);
+  const heading = target.slice(hash + 1);
+  return page ? `${page} > ${heading}` : heading;
+}
